const express = require('express');
const mysql = require('mysql2/promise');

const app = express();

const pool = mysql.createPool({
  host: process.env.DB_HOST || 'localhost',
  port: Number(process.env.DB_PORT || 3306),
  user: process.env.DB_USER || 'root',
  password: process.env.DB_PASS || '',
  database: process.env.DB_NAME || 'app',
  waitForConnections: true,
  connectionLimit: Number(process.env.DB_POOL_SIZE || 10),
  maxIdle: Number(process.env.DB_POOL_MAX_IDLE || 10),
  idleTimeout: Number(process.env.DB_POOL_IDLE_TIMEOUT_MS || 60000),
  queueLimit: 0
});

function escapeLike(s) {
  return String(s).replace(/[\\%_]/g, '\\$&');
}

app.get('/api/products/search', async (req, res) => {
  try {
    const qRaw = (req.query.q || '').toString().trim();
    if (!qRaw) return res.status(400).json({ error: 'Missing q' });

    const limit = Math.min(Math.max(parseInt(req.query.limit, 10) || 50, 1), 200);
    const offset = Math.min(Math.max(parseInt(req.query.offset, 10) || 0, 0), 100000);

    const q = escapeLike(qRaw);
    const like = `%${q}%`;

    const sql = `
      SELECT id, name, price, sku
      FROM products
      WHERE name LIKE ? ESCAPE '\\\\'
      ORDER BY name ASC
      LIMIT ? OFFSET ?
    `;

    const [rows] = await pool.execute(sql, [like, limit, offset]);
    res.json({ q: qRaw, count: rows.length, results: rows });
  } catch (err) {
    res.status(500).json({ error: 'Server error' });
  }
});

const port = Number(process.env.PORT || 3000);
